// USE CASE DIAGRAM NOTATION

// System Boundary
SYSTEM [SystemName] {
 // Use Cases (inside boundary)
 USECASE [UseCaseName1]
 USECASE [UseCaseName2]

 // Relationships
 USECASE [BaseCase] --(dashed)--> <<include>> USECASE [CommonBehavior]
 USECASE [Extension] --(dashed)--> <<extend>> USECASE [BaseCase]
 USECASE [ChildCase] --(solid triangle)--> USECASE [ParentCase]
}

// Actors (outside boundary)
ACTOR [ActorName1] --(solid)--> USECASE [UseCaseName1]
ACTOR [ActorName2] --(solid)--> USECASE [UseCaseName2]
